/**
 * Integration tests for MCP server auto-retrieve functionality
 * Tests the stdio interface and result formatting
 */

const { exec } = require('child_process');
const { promisify } = require('util');
const readline = require('readline');

const execAsync = promisify(exec);

/**
 * Helper to spawn MCP server and send JSON-RPC requests via stdio
 */
function sendMcpRequest(method, params) {
  return new Promise((resolve, reject) => {
    // Start MCP server
    const server = require('child_process').spawn('node', ['src/gsd-qdrant-mcp/index.js'], {
      stdio: ['pipe', 'pipe', 'pipe']
    });

    const rl = readline.createInterface({
      input: server.stdout,
      output: server.stderr,
      terminal: false
    });

    let responseData = '';
    let errorData = '';

    // Collect stderr (logs)
    server.stderr.on('data', (data) => {
      errorData += data.toString();
    });

    // Collect stdout (JSON-RPC responses)
    server.stdout.on('data', (data) => {
      responseData += data.toString();
    });

    // Send request
    const request = {
      jsonrpc: '2.0',
      id: 1,
      method,
      params
    };

    server.stdin.write(JSON.stringify(request) + '\n');

    // Wait for response
    setTimeout(() => {
      server.kill();

      try {
        const lines = responseData.trim().split('\n');
        const response = JSON.parse(lines[lines.length - 1]);
        resolve({ response, stderr: errorData });
      } catch (e) {
        reject(new Error(`Failed to parse response: ${responseData}`));
      }
    }, 5000); // 5 second timeout
  });
}

describe('S02-integration', () => {
  describe('auto_retrieve tool', () => {
    it('should return valid JSON-RPC response for auto_retrieve with simple task', async () => {
      const { response, stderr } = await sendMcpRequest('auto_retrieve', {
        task: 'Create a login component with email and password fields',
        limit: 3,
        maxQueries: 2,
        includeContent: false
      });

      // Verify JSON-RPC structure
      expect(response).toHaveProperty('result');
      expect(response.result).toHaveProperty('content');
      expect(Array.isArray(response.result.content)).toBe(true);

      // Verify response format
      const textContent = response.result.content.find(c => c.type === 'text');
      expect(textContent).toBeDefined();

      const parsedBody = JSON.parse(textContent.text);
      expect(parsedBody).toHaveProperty('task');
      expect(parsedBody).toHaveProperty('keywords');
      expect(parsedBody).toHaveProperty('queries');
      expect(parsedBody).toHaveProperty('results');
      expect(Array.isArray(parsedBody.results)).toBe(true);
    });

    it('should extract keywords correctly from authentication-related task', async () => {
      const { response } = await sendMcpRequest('auto_retrieve', {
        task: 'Implement JWT authentication with login and logout endpoints',
        limit: 3,
        maxQueries: 2,
        includeContent: false
      });

      const parsedBody = JSON.parse(response.result.content[0].text);

      // Should extract 'authentication' keyword
      expect(parsedBody.keywords).toContain('authentication');
      expect(parsedBody.keywords.length).toBeGreaterThan(0);
    });

    it('should handle component-related task and extract appropriate keywords', async () => {
      const { response } = await sendMcpRequest('auto_retrieve', {
        task: 'Build a reusable modal component with close button and backdrop',
        limit: 3,
        maxQueries: 2,
        includeContent: false
      });

      const parsedBody = JSON.parse(response.result.content[0].text);

      // Should extract 'component' keyword
      expect(parsedBody.keywords).toContain('component');
      expect(parsedBody.queries.length).toBeGreaterThan(0);
    });

    it('should return empty results when no matching context exists (fallback behavior)', async () => {
      const { response } = await sendMcpRequest('auto_retrieve', {
        task: 'This is a completely made up task with random words xyz abc def',
        limit: 3,
        maxQueries: 2,
        includeContent: false
      });

      const parsedBody = JSON.parse(response.result.content[0].text);

      // Should still return valid structure even if no matches found
      expect(parsedBody).toHaveProperty('results');
      expect(Array.isArray(parsedBody.results)).toBe(true);
    });

    it('should include content when includeContent=true for top result', async () => {
      const { response } = await sendMcpRequest('auto_retrieve', {
        task: 'Create a login component with email and password fields',
        limit: 3,
        maxQueries: 2,
        includeContent: true
      });

      const parsedBody = JSON.parse(response.result.content[0].text);

      // Top result should have content when includeContent=true
      if (parsedBody.results.length > 0) {
        expect(parsedBody.results[0]).toHaveProperty('content');
      }
    });

    it('should respect limit parameter', async () => {
      const { response } = await sendMcpRequest('auto_retrieve', {
        task: 'Create a login component with email and password fields',
        limit: 1,
        maxQueries: 2,
        includeContent: false
      });

      const parsedBody = JSON.parse(response.result.content[0].text);

      // Should return at most 'limit' number of results
      expect(parsedBody.results.length).toBeLessThanOrEqual(1);
    });

    it('should return error response on invalid input', async () => {
      const { response } = await sendMcpRequest('auto_retrieve', {
        task: '', // Empty task should trigger error handling
        limit: 3,
        maxQueries: 2,
        includeContent: false
      });

      // Should return isError: true for error responses
      expect(response.result).toHaveProperty('isError');
    });

    it('should handle special characters in task correctly', async () => {
      const { response } = await sendMcpRequest('auto_retrieve', {
        task: 'Create a form with special characters: <script>alert(1)</script> and symbols @#$%',
        limit: 3,
        maxQueries: 2,
        includeContent: false
      });

      const parsedBody = JSON.parse(response.result.content[0].text);

      // Should handle special characters without crashing
      expect(parsedBody).toHaveProperty('results');
      expect(Array.isArray(parsedBody.results)).toBe(true);
    });
  });

  describe('retrieve_context tool', () => {
    it('should return valid response for retrieve_context with query', async () => {
      const { response } = await sendMcpRequest('retrieve_context', {
        query: 'authentication login',
        limit: 3,
        includeContent: false
      });

      expect(response).toHaveProperty('result');
      expect(response.result).toHaveProperty('content');

      const textContent = response.result.content.find(c => c.type === 'text');
      expect(textContent).toBeDefined();

      const parsedBody = JSON.parse(textContent.text);
      expect(parsedBody).toHaveProperty('query');
      expect(parsedBody).toHaveProperty('results');
      expect(parsedBody.query).toBe('authentication login');
    });

    it('should respect includeContent parameter', async () => {
      const { response } = await sendMcpRequest('retrieve_context', {
        query: 'authentication login',
        limit: 3,
        includeContent: true
      });

      const parsedBody = JSON.parse(response.result.content[0].text);

      if (parsedBody.results.length > 0) {
        expect(parsedBody.results[0]).toHaveProperty('content');
      }
    });
  });

  describe('list_projects tool', () => {
    it('should return valid projects list', async () => {
      const { response } = await sendMcpRequest('list_projects', {});

      expect(response).toHaveProperty('result');
      expect(response.result).toHaveProperty('content');

      const textContent = response.result.content.find(c => c.type === 'text');
      expect(textContent).toBeDefined();

      const parsedBody = JSON.parse(textContent.text);
      expect(parsedBody).toHaveProperty('projects');
      expect(Array.isArray(parsedBody.projects)).toBe(true);
      expect(parsedBody).toHaveProperty('totalProjects');
      expect(typeof parsedBody.totalProjects).toBe('number');
    });
  });
});

